using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    unordered_map<long long, vector<vector<long long>>> graph;
    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long start = edge[2];
        long long end = edge[3];
        graph[u].push_back({v, start, end});
    }

    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> heap;
    heap.push({0, 0});
    unordered_map<long long, long long> visited;

    while (!heap.empty()) {
        auto current = heap.top();
        heap.pop();
        long long current_time = current.first;
        long long node = current.second;

        if (node == n - 1) {
            return current_time;
        }
        if (visited.find(node) != visited.end() && visited[node] <= current_time) {
            continue;
        }
        visited[node] = current_time;

        // Option 1: Stay at current node
        if (visited.find(node) == visited.end() || visited[node] > current_time + 1) {
            heap.push({current_time + 1, node});
        }

        // Option 2: Take available edges
        if (graph.find(node) != graph.end()) {
            for (const auto& edge : graph[node]) {
                long long v = edge[0];
                long long start = edge[1];
                long long end = edge[2];
                if (current_time >= start && current_time <= end) {
                    long long arrival_time = current_time + 1;
                    if (visited.find(v) == visited.end() || visited[v] > arrival_time) {
                        heap.push({arrival_time, v});
                    }
                } else if (current_time < start) {
                    long long arrival_time = start + 1;
                    if (visited.find(v) == visited.end() || visited[v] > arrival_time) {
                        heap.push({arrival_time, v});
                    }
                }
            }
        }
    }

    return -1;
}
