        visited[node] = current_time

        # Option 1: Stay at current node (only if it can lead to a better time)
        if current_time + 1 not in visited or visited.get(node, float('inf')) > current_time + 1:
            heapq.heappush(heap, (current_time + 1, node))

        # Option 2: Take available edges
