            if start <= current_time <= end:
                arrival_time = current_time + 1
                if v not in visited or visited.get(v, float('inf')) > arrival_time:
                    heapq.heappush(heap, (arrival_time, v))
            elif current_time < start:
                arrival_time = start + 1
                if v not in visited or visited.get(v, float('inf')) > arrival_time:
                    heapq.heappush(heap, (arrival_time, v))

    return -1
